        uint256 buyFeeRate_;
        /// The sell fee rate
        uint256 sellFeeRate_;
        /// Liquidity fee in basis points (0-10000, where 100 = 1%)
        uint256 liquidityFee_;
        /// Reserve fee in basis points (0-10000, where 100 = 1%)
        uint256 reserveFee_;
        //
        // Migrator Related
        //

        /// The WETH address
