        /// Portal V4 CL Locker (shared between UniV4 and PCS Infinity; contract file: PortalUniV4Locker.sol)
        address portalV4CLLocker_;
        /// V4 Hook (FlapV4Hook or FlapInfinityCLHook) — shared for all Uniswap V4 pools
        address v4CLHook_;
